class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def binaryTreePaths(root: TreeNode) -> list[str]:
    if not root:
        return []

    paths = []

    def dfs(node, current_path_str):
        if not node:
            return

        # Mevcut düğümün değerini yola ekle.
        # Eğer current_path_str boş değilse "->" ile birleştir.
        new_path_str = current_path_str + ( "->" if current_path_str else "" ) + str(node.val)

        # Eğer düğüm yaprak düğüm ise (çocuğu yoksa), yolu sonuç listesine ekle.
        if not node.left and not node.right:
            paths.append(new_path_str)
        else:
            # Yaprak düğüm değilse, sol ve sağ çocukları için özyinelemeli çağrı yap.
            dfs(node.left, new_path_str)
            dfs(node.right, new_path_str)

    dfs(root, "")
    return paths
